1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const toKey = ([x, y]: Cell): string => `${x},${y}`;
10	const fromKey = (key: string): Cell => {
11	  const [x, y] = key.split(",");
12	  return [Number(x), Number(y)];
13	};
14	
15	const survivesToNextGeneration = (neighbors: number, wasAlive: boolean): boolean =>
16	  neighbors === 3 || (neighbors === 2 && wasAlive);
17	
18	export function nextGeneration(liveCells: Cell[]): Cell[] {
19	  const liveKeys = new Set(liveCells.map(toKey));
20	  const neighborCounts = new Map<string, number>();
21	
22	  for (const [x, y] of liveCells) {
23	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
24	      const key = toKey([x + dx, y + dy]);
25	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
26	    }
27	  }
28	
29	  return Array.from(neighborCounts)
30	    .filter(([key, count]) => survivesToNextGeneration(count, liveKeys.has(key)))
31	    .map(([key]) => fromKey(key));
32	}
33

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells with only one neighbor each (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block stable (survival)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(new Set(result.map(c => c.join(",")))).toEqual(
18	      new Set(block.map(c => c.join(",")))
19	    );
20	    expect(result.length).toBe(4);
21	  });
22	  it("should rotate a horizontal blinker to vertical (survival + reproduction)", () => {
23	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
24	    const result = nextGeneration(horizontal);
25	    expect(new Set(result.map(c => c.join(",")))).toEqual(
26	      new Set(["0,0", "0,1", "0,2"])
27	    );
28	  });
29	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
30	    const lShape: [number, number][] = [[0, 0], [1, 0], [0, 1]];
31	    const result = nextGeneration(lShape);
32	    expect(new Set(result.map(c => c.join(",")))).toEqual(
33	      new Set(["0,0", "1,0", "0,1", "1,1"])
34	    );
35	  });
36	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
37	    // Plus shape: center cell has 4 live neighbors
38	    const plus: [number, number][] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
39	    const result = nextGeneration(plus);
40	    expect(result.map(c => c.join(","))).not.toContain("1,1");
41	  });
42	  it.todo("should handle negative coordinates");
43	});
